ody {\n  font-family: \"Muli\", sans-serif;\n  font-size: 15px;\n  line-height: 1.75;\n  margin: 0;\n  text-align: left;\n  background-color: #fff;\n  font-weight: 400;\n  color: #6c757d;\n}\n\n/*--------------------\n TYPOGRAPHY\n-----------------*/\n.h1,\n.h2,\n.h3,\n.h4,\n.h5,\n.h6,\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  font-family: \"Muli\", sans-serif;\n  font-weight: 700;\n  line-height: 1.35;\n  margin-bottom: 0.5rem;\n  color: #212529;\n}\n\n.h1,\nh1 {\n  font-size: 2.125rem;\n  line-height: 40px;\n}\n\n.h2,\nh2 {\n  font-size: 1.625rem;\n}\n\n.h3,\nh3 {\n  font-size: 1.375rem;\n}\n\n.h4,\nh4 {\n  font-size: 1.125rem;\n}\n\n.h5,\nh5 {\n  font-size: 0.9375rem;\n}\n\n.h6,\nh6 {\n  font-size: 0.75rem;\n}\n\n.lead {\n  font-size: 1.0625rem;\n  font-weight: 300;\n}\n\n.font-weight-500 {\n  font-weight: 500 !important;\n}\n\n.section-title {\n  font-size: 35px;\n  font-weight: 700;\n  text-transform: capitalize;\n  margin-bottom: 15px;\n}\n\n.bg-grey {\n  background: #F4F7FC;\n}\n\nimg {\n  vertical-align: middle;\n  border-style: none;\n}\n\n.img-thumbnail {\n  padding: 0.25rem;\n  border: 1px solid #dee2e6;\n  background-color: #fff;\n}\n\n.section-heading {\n  margin-bottom: 80px;\n}\n\n.section {\n  position: relative;\n  padding: 8.125rem 0;\n}\n\n@media (min-width: 768px) {\n  .section {\n    padding: 7.5rem 0;\n  }\n}\n.section-top {\n  padding-top: 8.125rem;\n}\n\n.section-bottom {\n  padding-bottom: 8.125rem;\n}\n\n@media (min-width: 768px) {\n  .section-top {\n    padding-top: 10.3125rem;\n  }\n}\n.btn {\n  font-size: 0.6875rem;\n  font-weight: 700;\n  position: relative;\n  text-transform: uppercase;\n  padding: 1rem 2.4rem;\n  border: 0.1rem solid transparent;\n  transition: all 0.2s ease-in-out;\n  letter-spacing: 0.5px;\n}\n\n.btn-circle {\n  display: inline-flex;\n  width: 4.20313rem !important;\n  height: 4.20313rem !important;\n  padding: 0 !important;\n  border-radius: 50%;\n  align-items: center;\n  justify-content: center;\n}\n\n.btn-outline-dark {\n  border: 1px solid #222;\n}\n\n.btn-outline-dark:hover {\n  background: #222 !important;\n  color: #fff !important;\n}\n\n.btn-white {\n  background: #fff;\n  color: #212529;\n}\n\n.btn-trans-white {\n  border: 1px solid #fff;\n  color: #fff;\n}\n.btn-trans-white:hover {\n  color: #fff;\n  opacity: 0.5;\n}\n\n.btn.btn-link {\n  color: #212529;\n}\n\n.btn:focus {\n  box-shadow: none !important;\n}\n\n.btn-circled {\n  border-radius: 75px;\n}\n\n.bg-primary,\n.btn-primary,\n.btn-white:hover {\n  background: #21c87a !important;\n  border-color: #21c87a !important;\n  color: #fff;\n}\n\n.bg-dark,\n.btn-primary:hover {\n  background: #232323 !important;\n  border-color: #232323 !important;\n  color: #fff;\n}\n\n.shadow-sm-2 {\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n\n.box-shadow {\n  box-shadow: 0 25px 100px -5px rgba(0, 0, 0, 0.15);\n}\n\n.bg-cover {\n  background-repeat: no-repeat;\n  background-position: 50%;\n  background-size: cover;\n}\n\n.bg-cover,\n.bg-overlay,\n.bg-overlay::before {\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n}\n\n.bg-overlay::before {\n  content: \"\";\n  opacity: 0.55;\n  background-color: #212529;\n}\n\n.mt-80 {\n  margin-top: 80px;\n}\n\n.mb-30 {\n  margin-bottom: 30px;\n}\n\n.bg-primary {\n  background: #21c87a !important;\n}\n\na {\n  color: #21c87a;\n  transition: 0.3s;\n}\n\na:hover,\na:focus {\n  outline: none;\n  text-decoration: none;\n  color: rgb(25.7768240343, 156.2231759657, 95.2961373391);\n}\n\n/*----------------------\n REDES SOCIALES (top-bar)\n-----------------------*/\n.header-socials {\n  line-height: 22px;\n  margin-bottom: 0px;\n}\n.header-socials li {\n  padding: 8px;\n}\n.header-socials li a {\n  color: #21c87a;\n}\n\n/*-----------------\n LOGO BAR\n-------------------*/\n.logo-bar {\n  padding: 30px 0px 60px;\n}\n\n.top-info-block {\n  margin-right: 30px;\n}\n.top-info-block h5,\n.top-info-block p {\n  margin-bottom: 0px;\n}\n\n.icon-block {\n  margin-right: 20px;\n  color: #21c87a;\n  font-size: 40px;\n  line-height: 20px;\n  font-weight: 400;\n}\n\n.top-info-block:last-child {\n  margin-right: 0px;\n}\n\n.header-bar {\n  overflow: visible;\n  position: relative;\n  padding-bottom: 30px;\n}\n\n.main-navigation {\n  margin-top: -40px;\n}\n\n/*-----------------------\n HOME-3\n---------------------------*/\n.header-white {\n  background: #21c87a;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  border-radius: 0px;\n}\n\n@media (max-width: 992px) {\n  .trans-navigation {\n    background: #21c87a;\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    border-radius: 0px;\n  }\n}\n\n.trans-navigation .navbar-brand h4,\n.site-navigation .navbar-brand h4,\n.site-navigation .navbar-brand h3,\n.trans-navigation .navbar-brand h3 {\n  color: #fff;\n}\n\n.banner-content.style-2 {\n  padding-top: 200px;\n}\n\n.trans-navigation .navbar-brand {\n  padding-top: 13px;\n}\n\n.site-navigation.header-white {\n  border-bottom: 1px solid transparent;\n}\n\n.site-navigation .navbar-brand {\n  padding-top: 13px;\n  margin-right: 20px;\n}\n\n.banner-content2 {\n  padding: 200px 0px;\n}\n.banner-content2 .display-4 {\n  color: #fff;\n  font-weight: 600;\n}\n.banner-content2 p.lead {\n  color: #fff;\n}\n\n/* =========================\nPRELOADER\n=======================*/\n#page-loader {\n  background: #fff;\n  height: 100%;\n  width: 100%;\n  position: fixed;\n  z-index: 1050;\n}\n\n.loader-icon {\n  background: none repeat scroll 0 0 #fff;\n  border-bottom: 3px solid rgba(19, 19, 19, 0.1) !important;\n  border-left: 3px solid rgba(19, 19, 19, 0.1) !important;\n  border-radius: 100px;\n  -moz-border-radius: 100px;\n  -webkit-border-radius: 100px;\n  -o-border-radius: 100px;\n  -ms-border-radius: 100px;\n  border-right: 3px solid #1453F2 !important;\n  border-top: 3px solid rgba(19, 19, 19, 0.1) !important;\n  height: 50px;\n  left: 50%;\n  margin: -20px 0 0 -20px;\n  position: absolute;\n  text-align: center;\n  top: 50%;\n  width: 50px;\n  -webkit-transform: translate(-50%, -50%);\n  -ms-transform: translate(-50%, -50%);\n  transform: translate(-50%, -50%);\n}\n\n.colored-border {\n  border-color: #fff;\n}\n\n.fa-spin {\n  -webkit-animation: fa-spin 1s infinite linear;\n  animation: fa-spin 1s infinite linear;\n}\n\n@-webkit-keyframes fa-spin {\n  0% {\n    -webkit-transform: rotate(0deg);\n    transform: rotate(0deg);\n  }\n  100% {\n    -webkit-transform: rotate(359deg);\n    transform: rotate(359deg);\n  }\n}\n@keyframes fa-spin {\n  0% {\n    -webkit-transform: rotate(0deg);\n    transform: rotate(0deg);\n  }\n  100% {\n    -webkit-transform: rotate(359deg);\n    transform: rotate(359deg);\n  }\n}\n/*--------------------------\nPAGE BANNER\n--------------------------*/\n.page-banner-area {\n  padding: 180px 0px;\n}\n\n.page-contact {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/p-6.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-service {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/service.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-about {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/about.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-pricing {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/img2.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-project {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/p-4.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-banner-content h1 {\n  color: #fff;\n}\n\n.page-banner-content p {\n  color: #eee;\n}\n\n.form-control {\n  border-radius: 0px;\n  height: 45px;\n}\n\n/*-------------------\n   MENU\n----------------------*/\n.navbar-toggler-icon {\n  display: inline-block;\n  width: 1.5em;\n  height: 1.5em;\n  content: \"\";\n  vertical-align: middle;\n  background: no-repeat 50%;\n  background-size: 100% 100%;\n}\n\n.navbar-dark .navbar-toggler {\n  color: #fff;\n  border-color: rgba(255, 255, 255, 0.1);\n  padding: 10px 12px;\n}\n.navbar-dark .navbar-toggler:focus {\n  outline: 0;\n}\n\n.main-nav {\n  margin-bottom: -45px;\n  z-index: 999;\n}\n\n.navbar-nav .nav-link {\n  padding-right: 1rem !important;\n  padding-left: 1rem !important;\n  transition: 0.3s;\n}\n\n.navbar-dark .navbar-nav .nav-link {\n  color: #fff;\n  font-weight: 700;\n  letter-spacing: 0.5px;\n  text-transform: uppercase;\n}\n\n.rounded-radius {\n  border-radius: 5px;\n}\n\n.navbar {\n  position: relative;\n  padding: 1rem 1rem;\n}\n.navbar:before {\n  position: absolute;\n  z-index: -1;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n  content: \"\";\n  transition: opacity 0.15s linear;\n  opacity: 0;\n  border-bottom: 1px solid rgba(0, 0, 0, 0.1);\n  background-color: #fff;\n}\n\n.dropdown-toggle::after {\n  margin-left: 0.255em;\n  vertical-align: 1px;\n  content: \"\\f078\";\n  border: 0;\n  font-family: \"Font Awesome 5 Free\";\n  font-size: 12px;\n}\n\n.fixed-top {\n  position: fixed;\n  z-index: 1030;\n  right: 0;\n  left: 0;\n}\n\n.navbar-dark {\n  color: #fff;\n}\n\n.navbar-light {\n  color: #212529;\n}\n.navbar-light:before {\n  opacity: 1;\n}\n\n.navbar .nav-item-divider {\n  display: none;\n}\n.navbar .nav-item-divider .nav-link {\n  opacity: 0.25;\n}\n\n.header-bar.fixed-header .main-navigation {\n  position: fixed;\n  left: 0;\n  top: 0;\n  width: 100%;\n  background: rgba(20, 27, 40, 0.9);\n  border-color: transparent;\n}\n\n/*-------------------\n  DROPDOWN MENU\n----------------------*/\n.has-dropdown .dropdown-menu {\n  border: none;\n  box-shadow: 0 0 25px 0 rgba(0, 0, 0, 0.08);\n  padding: 0;\n  margin: 0;\n}\n@media (max-width: 992px) {\n  .has-dropdown .dropdown-menu {\n    text-align: center;\n    float: left !important;\n    width: 100%;\n    margin: 0;\n  }\n}\n.has-dropdown .dropdown-menu a {\n  font-weight: normal;\n  color: #808080;\n  padding: 10px 20px;\n  -webkit-transition: all 0.3s ease;\n  -moz-transition: all 0.3s ease;\n  -ms-transition: all 0.3s ease;\n  -o-transition: all 0.3s ease;\n  transition: all 0.3s ease;\n  border-bottom: 1px solid #eee;\n  border-radius: 4px;\n}\n.has-dropdown .dropdown-menu a:focus, .has-dropdown .dropdown-menu a:hover {\n  background: #21c87a;\n  color: #fff;\n}\n\n.dropleft .dropdown-menu,\n.dropright .dropdown-menu {\n  margin: 0;\n}\n\n.dropleft .dropdown-toggle::before,\n.dropright .dropdown-toggle::after {\n  font-weight: bold;\n  font-family: \"Font Awesome 5 Free\";\n  border: 0;\n  font-size: 10px;\n  vertical-align: 1px;\n}\n\n.dropleft .dropdown-toggle::before {\n  content: \"\\f053\";\n  margin-right: 7px;\n}\n\n.dropright .dropdown-toggle::after {\n  content: \"\\f054\";\n  margin-left: 7px;\n}\n\n.dropdown-item {\n  padding: 0.6rem 1.4rem;\n  text-transform: uppercase;\n  font-size: 12px;\n  font-weight: 700;\n}\n\n.dropdown-submenu:hover > .dropdown-item,\n.dropdown-item:hover {\n  background: #21c87a;\n  color: #fff !important;\n}\n\n.dropdown-item.active {\n  text-decoration: underline;\n  background-color: transparent;\n  color: inherit;\n}\n\n.dropdown-submenu.active > .dropdown-toggle {\n  text-decoration: underline;\n  color: inherit;\n}\n\nul.dropdown-menu li {\n  padding-left: 0px !important;\n}\n\n@media (min-width: 992px) {\n  .dropdown-menu {\n    transition: all 0.2s ease-in, visibility 0s linear 0.2s, transform 0.2s linear;\n    display: block;\n    visibility: hidden;\n    opacity: 0;\n    min-width: 200px;\n    transform: translateY(15px);\n  }\n  .dropdown:hover > .dropdown-menu {\n    visibility: visible;\n    transition: all 0.35s ease 0s;\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n/*----------------------\n BANNER STYLE\n-----------------------*/\n.py-7 {\n  padding: 7.5rem 0;\n}\n\n.py-8 {\n  padding: 8.5rem 0;\n}\n\n.main-banner h5 {\n  margin-bottom: 20px;\n}\n.main-banner h1.display-4 {\n  line-height: 65px;\n}\n\n.main-banner p.lead,\n.banner-content p.lead {\n  margin-bottom: 2.5rem !important;\n}\n\n/*-------------------------\n HOME -2 \n-----------------------------*/\n#banner {\n  position: relative;\n  background: url(\"/images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.banner-content {\n  padding: 150px 0px;\n  padding-right: 30px;\n}\n.banner-content p {\n  color: #eee;\n  padding-right: 80px;\n  margin-bottom: 30px !important;\n}\n.banner-content .display-4 {\n  color: #fff;\n  font-weight: 600;\n}\n\n#banner .overlay {\n  opacity: 0.7;\n}\n\n.banner-contact-form {\n  padding: 45px 40px;\n  margin-top: 30px;\n}\n.banner-contact-form .form-control {\n  border-radius: 0px;\n  height: 45px;\n}\n.banner-contact-form textarea.form-control {\n  height: auto;\n}\n\n#banner-3 {\n  position: relative;\n  background: url(\"../images/banner/banner.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n#banner-4 {\n  position: relative;\n  background: url(\"../images/banner/banner-2.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n/*----------------------\n FEATURE STYLE\n-----------------------*/\n.img-icon-block {\n  position: relative;\n}\n.img-icon-block:before {\n  position: absolute;\n  content: \"\";\n  top: -27px;\n  background-color: #21c87a;\n  opacity: 0.3;\n  width: 80px;\n  right: 70px;\n  height: 80px;\n  border-radius: 50%;\n  z-index: 1;\n}\n.img-icon-block i {\n  font-size: 58px;\n  z-index: 2 !important;\n  color: #333;\n  position: relative;\n}\n\n/*--------------------------\nABOUT-2\n---------------------------*/\n#about .img-block {\n  position: relative;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n#about .img-block img {\n  border: 5px solid #21c87a;\n}\n\n.pt-6 {\n  padding-top: 4.5rem;\n}\n\n.img-icon i {\n  font-size: 60px;\n}\n\n/*----------------------\n SERVICE\n-----------------------*/\nh5.subtitle {\n  color: #21c87a;\n  margin-bottom: 10px;\n  font-weight: 300;\n}\n\n.service-heading {\n  margin-bottom: 50px;\n}\n\n.service-images {\n  margin-bottom: -200px;\n  border: 10px solid #fff;\n  z-index: 9999;\n}\n\n.service-content {\n  padding-top: 60px;\n  padding-left: 15px;\n}\n.service-content h1 {\n  margin-bottom: 20px;\n  margin-top: 15px;\n}\n\n.service-icon {\n  margin-right: 20px;\n  color: #fff;\n  font-size: 25px;\n  width: 50px;\n  height: 50px;\n  background: #21c87a;\n  text-align: center;\n  border-radius: 50%;\n  padding-top: 5px;\n}\n\n.service-block {\n  margin-bottom: 50px;\n}\n\n.service-inner-content h4 {\n  text-transform: uppercase;\n}\n\n/*----------------------\n WEB SERVICES\n-----------------------*/\n#services-2 {\n  position: relative;\n  background: url(\"../images/bg/6.jpg\") no-repeat fixed 50% 50%;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n#services-2:before {\n  position: absolute;\n  content: \"\";\n  left: 0px;\n  top: 0px;\n  width: 100%;\n  height: 100%;\n  background-image: linear-gradient(30deg, rgba(121, 110, 255, 0.95) 0%, rgba(33, 200, 122, 0.95) 100%);\n}\n\n.web-service-block {\n  text-align: center;\n  padding: 35px 25px;\n  transition: 0.3s;\n  border-radius: 10px;\n  border: 1px solid rgba(255, 255, 255, 0.05);\n  margin-bottom: 10px;\n}\n.web-service-block i {\n  font-size: 70px;\n  margin-bottom: 30px;\n  display: block;\n  color: #fff;\n}\n.web-service-block h3 {\n  color: #fff;\n  transition: 0.3s;\n}\n.web-service-block p {\n  color: #eee;\n  margin-top: 15px;\n  transition: 0.3s;\n}\n.web-service-block:hover {\n  background: #fff;\n  border-color: transparent;\n}\n.web-service-block:hover i {\n  color: #21c87a;\n}\n.web-service-block:hover h3 {\n  color: #111;\n}\n.web-service-block:hover p {\n  color: #111;\n}\n\n.service-img {\n  margin-bottom: -200px;\n  border: 10px solid #fff;\n  z-index: 9999;\n}\n\n/*----------------------\n SECCIÓN PROYECTOS DESTACADOS\n-----------------------*/\n#projects-wrap {\n  position: relative;\n  background: url(\"../images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n#projects-wrap p.lead {\n  color: #a9a9a9 !important;\n}\n\n.overlay {\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 100%;\n  height: 100%;\n  background: rgba(0, 0, 0, 0.92);\n}\n\n.overlay.feature-overlay {\n  background-image: linear-gradient(30deg, rgba(121, 110, 255, 0.95) 0%, rgba(33, 200, 122, 0.95) 100%);\n  opacity: 0.9;\n}\n\n#projects {\n  margin-top: -60px;\n}\n\n.single-project img {\n  border-radius: 10px;\n}\n\n.project-content {\n  text-align: center;\n  padding: 40px 20px;\n  position: relative;\n}\n.project-content .btn {\n  padding: 0.7rem 1.7rem;\n  border-radius: 25px;\n}\n.project-content p {\n  margin-top: 20px;\n}\n.project-content h4 {\n  text-transform: capitalize;\n}\n\n.project-content-block {\n  padding: 70px 40px;\n  margin-left: -120px;\n  background: #F4F7FC;\n  position: absolute;\n  bottom: -70px;\n  border: 15px solid #fff;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n.project-content-block h4 {\n  color: #21c87a;\n}\n.project-content-block p {\n  margin-top: 25px;\n}\n\n/*-------------------------\n PORTFOLIO-2\n---------------------------*/\n.single-work {\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n}\n\n.overlay-content-block {\n  position: absolute;\n  content: \"\";\n  bottom: 20px;\n  width: 100%;\n  left: 30px;\n  padding: 30px 20px;\n  background: #fff;\n  opacity: 0;\n  visibility: hidden;\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n  border-radius: 5px 0px 0px 5px;\n}\n.overlay-content-block a {\n  width: 50px;\n  height: 50px;\n  display: inline-block;\n  text-align: center;\n  padding-top: 12px;\n  border-radius: 100%;\n  position: absolute;\n  left: 30px;\n  top: -23px;\n  background: #21c87a;\n  color: #fff;\n}\n.overlay-content-block h4 {\n  margin-bottom: 0px;\n  margin-top: 10px;\n}\n\n.work-block {\n  position: relative;\n  border: 5px solid #fff;\n}\n.work-block img {\n  width: 100%;\n  border-radius: 5px;\n}\n.work-block:hover .overlay-content-block {\n  opacity: 1;\n  visibility: visible;\n}\n\n/* ==============================\n  SINGEL PROJECTS\n=============================*/\n.project-details-info {\n  margin: 40px 0px;\n}\n\n.info-block-2 {\n  float: left;\n  margin-right: 65px;\n  margin-bottom: 40px;\n}\n\n.project-info ul {\n  margin-top: 40px;\n}\n.project-info ul li {\n  margin-bottom: 30px;\n  padding-right: 20px;\n}\n\n.project-lg-images img {\n  width: 100%;\n}\n\n/*----------------------\n PROCESS\n-----------------------*/\n.process-block {\n  text-align: center;\n}\n.process-block img {\n  border-radius: 5px;\n  margin-bottom: 30px;\n}\n.process-block h3 {\n  margin-bottom: 15px;\n}\n\n/*----------------------\n PRICING\n-----------------------*/\n.price-block {\n  margin: 20px 0px 30px;\n}\n.price-block h2 {\n  font-size: 80px;\n  font-weight: 700;\n  position: relative;\n  display: inline-block;\n}\n.price-block h2 small {\n  position: absolute;\n  top: 20px;\n  font-size: 16px;\n  left: -9px;\n}\n.price-block h6 {\n  font-size: 14px;\n  border-top: 1px solid #eee;\n  border-bottom: 1px solid #eee;\n  padding: 7px;\n  text-transform: capitalize;\n  width: 50%;\n  margin: 10px auto;\n}\n\n.price-features {\n  margin: 30px 0px 50px;\n}\n.price-features li {\n  font-size: 16px;\n  padding: 5px 0px;\n  position: relative;\n  padding-left: 30px;\n}\n.price-features li:before {\n  position: absolute;\n  content: \"\\f00c\";\n  font-family: \"Font Awesome 5 Free\";\n  left: 0px;\n  top: 5px;\n  color: #21c87a;\n  font-weight: 900;\n}\n\n.pricing-block .price-features li {\n  padding-left: 0px;\n}\n.pricing-block .price-features li:before {\n  display: none;\n}\n\n/*--------------------------\nPRICING-2\n---------------------------*/\n.pricing-box {\n  border: 1px solid #eee;\n  padding: 60px;\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n}\n.pricing-box .price-block h2 span {\n  font-size: 12px;\n  font-weight: normal;\n  text-transform: capitalize;\n}\n.pricing-box:hover {\n  background: rgb(29, 28, 28);\n  border-color: rgb(29, 28, 28);\n}\n.pricing-box:hover .price-features li {\n  color: #eee;\n}\n.pricing-box:hover .price-block h2 {\n  color: #fff;\n}\n.pricing-box:hover h3 {\n  color: #fff;\n}\n.pricing-box:hover .btn {\n  background: #fff !important;\n  color: #000 !important;\n}\n\n/*----------------------\n BLOG SECTION\n-----------------------*/\n.blog-box {\n  position: relative;\n}\n.blog-box .blog-img-box img {\n  border-radius: 5px;\n  box-shadow: 0 7px 12px rgba(0, 0, 0, 0.08);\n}\n\n.single-blog {\n  padding-top: 25px;\n  position: relative;\n}\n\n.bg-light .single-blog {\n  padding: 40px;\n  text-align: center;\n  border-bottom: 1px solid #eee;\n}\n\n.blog-content ul {\n  margin-bottom: 10px;\n}\n.blog-content a h3 {\n  transition: all 0.3s ease 0s;\n  margin: 15px 0px;\n}\n.blog-content p {\n  margin: 20px 0px;\n}\n.blog-content:hover a h3 {\n  color: #21c87a;\n}\n.blog-content h6 span {\n  display: inline-block;\n  padding-left: 10px;\n}\n.blog-content h6 span:after {\n  display: none;\n}\n\n/*------------------------------------\nSECTION TESTIMONIAL\n-------------------------------------*/\n#section-testimonial {\n  padding-bottom: 120px;\n  background: #F9FAFF;\n}\n\n.mb25 {\n  margin-bottom: 25px;\n}\n\n.test-inner {\n  position: relative;\n  padding: 30px;\n  background: #fff;\n  border-top-right-radius: 35px;\n  margin-bottom: 25px;\n  -webkit-transition: all 0.7s ease;\n  -o-transition: all 0.7s ease;\n  transition: all 0.7s ease;\n}\n.test-inner:hover {\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n.test-inner i {\n  font-size: 60px;\n  opacity: 0.09;\n  position: absolute;\n  right: 40px;\n  bottom: 20px;\n}\n\n.test-author-thumb {\n  margin-bottom: 15px;\n}\n.test-author-thumb img {\n  width: 90px;\n  height: 90px;\n  border-radius: 100%;\n  border: 1px dotted #ddd;\n  padding: 5px;\n}\n\n.test-author-info {\n  margin-left: 20px;\n  margin-top: 20px;\n}\n\n/*----------------------\n TETSIMONIAL-2\n-------------------------*/\n.testimonial .content img {\n  margin: 0 auto 30px;\n  border: 3px solid #fff;\n}\n\n.img-md {\n  width: 120px;\n  height: 120px;\n  border-radius: 100%;\n}\n\n/*---------------------------\nCONTACT PAGE\n-----------------------------*/\n#contact-info {\n  padding-top: 90px;\n}\n\n.contact-info-block {\n  border: 1px solid #eee;\n  padding: 40px 20px;\n  border-radius: 5px;\n}\n.contact-info-block h4 {\n  margin-bottom: 0px;\n}\n.contact-info-block i {\n  font-size: 40px;\n  margin-bottom: 20px;\n  display: block;\n  color: #21c87a;\n}\n\n.form-control:focus, .form-control:hover {\n  border-color: #21c87a;\n  box-shadow: none;\n}\n\n/* --------------\n    MAP\n-----------------*/\n#map {\n  height: 400px;\n  width: 100%;\n}\n\n/*----------------------\n FOOTER\n-----------------------*/\n#footer {\n  padding: 80px 0px;\n  position: relative;\n}\n#footer .footer-brand {\n  font-size: 30px;\n}\n#footer .footer-links {\n  padding-left: 0;\n  list-style-type: none;\n}\n\n#footer {\n  background: url(\"../images/bg/10.jpg\");\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.footer-overlay {\n  background: #111;\n  opacity: 0.94;\n}\n\n.footer-widget p {\n  color: #888;\n  margin-top: 20px;\n  margin-bottom: 20px;\n  line-height: 32px;\n  font-size: 14px;\n}\n.footer-widget h3 {\n  color: #fff;\n  margin-bottom: 30px;\n}\n\n.footer-links a {\n  color: #888;\n  line-height: 38px;\n  font-size: 14px;\n  text-transform: capitalize;\n}\n.footer-links i {\n  width: 25px;\n}\n\n.footer-copy {\n  color: #888;\n  font-size: 16px;\n  position: relative;\n  margin-bottom: 0;\n  display: inline-block;\n}\n.footer-copy:before {\n  position: absolute;\n  content: \"\";\n  right: calc(100% + 30px);\n  top: 16px;\n  width: 2000%;\n  height: 1px;\n  height: 1px;\n  background: #94959a;\n}\n\n.current-year {\n  color: #21c87a !important;\n}\n\n/*-----------------------------\n SCROLL TO TOP\n--------------------------------*/\n.scroll-to-top {\n  position: fixed;\n  content: \"\";\n  right: 30px;\n  bottom: 50px;\n  z-index: 999;\n  background: #21c87a;\n  color: #fff !important;\n  border-radius: 100%;\n  opacity: 0;\n}\n.scroll-to-top i {\n  width: 50px;\n  height: 50px;\n  border-radius: 100%;\n  text-align: center;\n  font-size: 22px;\n  line-height: 50px;\n  display: block;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n\n.scroll-to-top:hover,\n.scroll-to-top:focus {\n  text-decoration: none;\n}\n\n.reveal {\n  transition: all 0.3s;\n  cursor: pointer;\n  opacity: 1;\n}\n\n/*----------------------------------\n  LARGE DESKTOP: max-width 1200px\n----------------------------------*/\n@media (max-width: 1200px) {\n  .navbar {\n    text-align: center;\n  }\n  .navbar .nav-item-divider {\n    display: block;\n  }\n}\n/*----------------------------------\n  DESKTOP/TABLET LANDSCAPE: max-width 992px\n----------------------------------*/\n@media (max-width: 992px) {\n  .section-title {\n    font-size: 30px;\n  }\n  .background-text {\n    font-size: 60px;\n  }\n  .main-banner h1.display-4 {\n    line-height: 62px;\n    font-size: 30px;\n  }\n  .main-nav .navbar-brand h4 {\n    color: #fff;