work-wrap p.lead {\n    margin-bottom: 40px;\n  }\n  .navbar-toggler:focus {\n    outline: none;\n  }\n}\n/* Custom, iPhone Retina */\n@media (max-width: 480px) {\n  .bg-light {\n    background: transparent !important;\n  }\n  .main-navigation {\n    margin-top: 40px;\n  }\n  a.navbar-brand h4 {\n    color: #fff;\n  }\n  .top-info-block {\n    text-align: center;\n    margin: 10px 0px;\n    clear: both;\n  }\n  .icon-block {\n    margin-right: 0px;\n    margin-bottom: 10px;\n  }\n  .main-navigation {\n    margin-top: 20px;\n  }\n  .main-nav .navbar-brand h4 {\n    color: #fff;\n    margin-top: 10px;\n  }\n  .section-title {\n    font-size: 22px;\n  }\n  .banner-contact-form {\n    padding: 45px 15px !important;\n  }\n  .feature-block {\n    margin-bottom: 80px;\n  }\n  .service-img {\n    margin-bottom: 0px;\n  }\n  .service-content {\n    padding-bottom: 70px;\n  }\n  .process-block,\n  .pricing-block {\n    margin-bottom: 40px;\n  }\n  .pricing-block.zoom-in {\n    -webkit-transform: none;\n    -ms-transform: none;\n    -o-transform: none;\n    transform: none;\n  }\n  .section-heading {\n    margin-bottom: 30px;\n  }\n  .project-content-block {\n    text-align: center;\n    margin-left: 0px;\n    padding: 70px 20px;\n    position: relative;\n    bottom: 0px;\n    margin-top: 30px;\n  }\n  .project-content-block h4 {\n    font-size: 14px;\n  }\n  .testimonial-heading {\n    margin-bottom: 50px;\n  }\n  .blog-box {\n    margin-bottom: 50px;\n  }\n  .footer-copy {\n    text-align: center;\n  }\n  .footer-copy:before {\n    display: none;\n  }\n  .about-block {\n    margin-top: 30px;\n  }\n  .banner-content .display-4 {\n    font-size: 28px;\n    line-height: 38px;\n  }\n  .banner-content p {\n    padding-right: 0px;\n  }\n  .pricing-box {\n    margin-top: 30px;\n  }\n  .main-navigation.menu-2 {\n    margin-top: 20px;\n    position: absolute;\n    width: 100%;\n  }\n  .navbar-collapse.collapse.show {\n    padding-bottom: 30px;\n    background: #21c87a;\n  }\n  .web-service-block {\n    margin-bottom: 30px;\n  }\n  .section {\n    padding: 60px 0px;\n  }\n  .section-bottom {\n    padding-bottom: 60px;\n  }\n  .section-top {\n    padding-top: 60px;\n  }\n  .main-banner h1.display-4 {\n    line-height: 42px;\n    font-size: 30px;\n  }\n  #projects {\n    margin-top: 60px;\n  }\n  .img-icon-block:before {\n    right: auto;\n  }\n  #feature {\n    padding-bottom: 0px;\n  }\n  .page-banner-area {\n    padding: 160px 0px 110px;\n  }\n  .display-4 {\n    font-size: 30px;\n  }\n  .info-block-2 {\n    margin-right: 35px;\n    margin-bottom: 40px;\n  }\n  #map {\n    margin-top: 40px;\n  }\n  .contact-info-block {\n    margin-bottom: 25px;\n  }\n  #work-wrap p.lead {\n    margin-bottom: 40px;\n  }\n  .navbar-toggler:focus {\n    outline: none;\n  }\n}","// =============================================================================\r\n// _typography.scss\r\n// Establece la base tipográfica y de reset del documento.\r\n// Importa la fuente Muli desde Google Fonts y define:\r\n//   - Reset mínimo de html/body\r\n//   - Escala de titulares h1–h6 (tamaños en rem)\r\n//   - Clase .section-title para los títulos de sección de landing\r\n//   - Clase .bg-grey (fondo alternado de secciones — fuente canónica)\r\n//\r\n// Índice de secciones del sistema de estilos completo:\r\n// ------------------------------------------------------\r\n//  01. Reset global (html, body)\r\n//  02. Tipografía (h1–h6, .lead, .section-title)\r\n//  03. Botones       → _common.scss\r\n//  04. Homepage      → _header.scss, _slider.scss, _backgrounds.scss\r\n//  05. Features      → _service.scss\r\n//  06. Servicios     → _service.scss\r\n//  07. About         → _about.scss\r\n//  08. Pricing       → _pricing.scss\r\n//  09. Testimonials  → _testimonial.scss\r\n//  10. Blog          → _blog.scss\r\n//  11. Contacto      → _contact.scss\r\n//  12. Footer        → _footer.scss\r\n// =============================================================================\r\n\r\n\r\n// Fonts \r\n@import url('https://fonts.googleapis.com/css?family=Muli:300,400,500,700,900');\r\n\r\n\r\n\r\nhtml {\r\n    font-family: sans-serif;\r\n    line-height: 1.15;\r\n    -webkit-text-size-adjust: 100%;\r\n    -ms-text-size-adjust: 100%;\r\n    -ms-overflow-style: scrollbar;\r\n    -webkit-tap-highlight-color: rgba(0, 0, 0, 0)\r\n}\r\n\r\nbody {\r\n     font-family: $secondary-font;\r\n    font-size: 15px;\r\n    line-height: 1.75;\r\n    margin: 0;\r\n    text-align: left;\r\n    background-color: #fff;\r\n    font-weight: 400;\r\n    color: $black-light;\r\n}\r\n\r\n/*--------------------\r\n TYPOGRAPHY\r\n-----------------*/\r\n\r\n.h1,\r\n.h2,\r\n.h3,\r\n.h4,\r\n.h5,\r\n.h6,\r\nh1,\r\nh2,\r\nh3,\r\nh4,\r\nh5,\r\nh6 {\r\n   \r\n     font-family: $primary-font; \r\n    font-weight: 700;\r\n    line-height: 1.35;\r\n    margin-bottom: .5rem;\r\n    color: $black;\r\n}\r\n\r\n.h1,\r\nh1 {\r\n    font-size: 2.125rem;\r\n    line-height: 40px;\r\n}\r\n\r\n.h2,\r\nh2 {\r\n    font-size: 1.625rem;\r\n}\r\n\r\n.h3,\r\nh3 {\r\n    font-size: 1.375rem;\r\n}\r\n\r\n.h4,\r\nh4 {\r\n    font-size: 1.125rem;\r\n}\r\n\r\n.h5,\r\nh5 {\r\n    font-size: .9375rem;\r\n}\r\n\r\n.h6,\r\nh6 {\r\n    font-size: .75rem;\r\n}\r\n\r\n.lead {\r\n    font-size: 1.0625rem;\r\n    font-weight: 300;\r\n}\r\n\r\n.font-weight-500 {\r\n    font-weight: 500 !important;\r\n}\r\n\r\n.section-title {\r\n    font-size: 35px;\r\n    font-weight: 700;\r\n    text-transform: capitalize;\r\n    margin-bottom: 15px;\r\n}\r\n\r\n.bg-grey {\r\n    background: $secondary-color;\r\n}","// =============================================================================\n// _variables.scss\n// Token de diseño centralizados del proyecto OASIS.\n// Modificar aquí propaga el cambio a todo el sistema de estilos.\n// =============================================================================\n\n\n// --- Colores ------------------------------------------------------------------\n\n$light:             #fff;           // Blanco puro (fondos, texto sobre primario)\n$primary-color:     #21c87a;        // Verde OASIS — color de marca principal\n$secondary-color:   #F4F7FC;        // Gris muy claro — fondos de secciones alternas\n$black:             #212529;        // Negro suave Bootstrap — titulares\n$black-light:       #6c757d;        // Gris medio Bootstrap — texto de cuerpo\n$black-lighter:     #888;           // Gris claro — texto secundario / captions\n\n\n// --- Bordes -------------------------------------------------------------------\n\n$border-color:      #eee;           // Borde neutro para tarjetas y separadores\n\n\n// --- Tipografía ---------------------------------------------------------------\n// NOTA: $primary-font y $secondary-font apuntan actualmente a la misma familia\n// (Muli). Si en el futuro se diferencian titulares de texto de cuerpo, basta\n// con actualizar el valor de $secondary-font aquí.\n\n$primary-font:   'Muli', sans-serif;  // Familia para titulares (h1–h6)\n$secondary-font: 'Muli', sans-serif;  // Familia para texto de cuerpo\n","// =============================================================================\n// _common.scss\n// Estilos compartidos reutilizables a lo largo de todas las páginas.\n// Incluye: layout de secciones, botones, utilidades de fondo y helpers.\n// =============================================================================\n\n\n// -----------------------------------------------------------------------------\n// IMÁGENES\n// -----------------------------------------------------------------------------\n\n// Elimina el gap vertical que los navegadores añaden a imágenes inline\nimg {\n  vertical-align: middle;\n  border-style: none;\n}\n\n// Miniatura con borde y padding (usada en galerías / tarjetas de proyecto)\n.img-thumbnail {\n  padding: .25rem;\n  border: 1px solid #dee2e6;\n  background-color: $light;\n}\n\n\n// -----------------------------------------------------------------------------\n// LAYOUT DE SECCIONES\n// .section       → sección de página completa con padding vertical generoso\n// .section-top   → sólo padding superior (secciones de apertura)\n// .section-bottom → sólo padding inferior (secciones de cierre)\n// .section-heading → contenedor del titular + subtítulo de cada sección\n// -----------------------------------------------------------------------------\n\n.section-heading {\n  margin-bottom: 80px;\n}\n\n.section {\n  position: relative;\n  padding: 8.125rem 0;\n}\n\n// Reduce padding en tablets\n@media (min-width: 768px) {\n  .section {\n    padding: 7.5rem 0;\n  }\n}\n\n.section-top {\n  padding-top: 8.125rem;\n}\n\n.section-bottom {\n  padding-bottom: 8.125rem;\n}\n\n@media (min-width: 768px) {\n  .section-top {\n    padding-top: 10.3125rem;\n  }\n}\n\n\n// -----------------------------------------------------------------------------\n// BOTONES\n// Extiende el sistema de botones de Bootstrap con las variantes de marca OASIS.\n// -----------------------------------------------------------------------------\n\n// Base: sobreescribe padding y tamaño de letra de Bootstrap\n.btn {\n  font-size: .6875rem;\n  font-weight: 700;\n  position: relative;\n  text-transform: uppercase;\n  padding: 1rem 2.4rem;\n  border: 0.1rem solid transparent;\n  transition: all 0.2s ease-in-out;\n  letter-spacing: .5px;\n}\n\n// Botón circular (icono) — usa !important para sobreescribir Bootstrap\n.btn-circle {\n  display: inline-flex;\n  width: 4.20313rem !important;\n  height: 4.20313rem !important;\n  padding: 0 !important;\n  border-radius: 50%;\n  align-items: center;\n  justify-content: center;\n}\n\n// Borde oscuro con hover relleno\n.btn-outline-dark {\n  border: 1px solid #222;\n}\n\n.btn-outline-dark:hover {\n  background: #222 !important;\n  color: $light !important;\n}\n\n// Botón blanco — fondo blanco con texto oscuro; hover → color primario\n.btn-white {\n  background: $light;\n  color: $black;\n}\n\n// Botón translúcido sobre fondos con imagen\n.btn-trans-white {\n  border: 1px solid $light;\n  color: $light;\n\n  &:hover {\n    color: $light;\n    opacity: .5;\n  }\n}\n\n// .btn.btn-link → apariencia de enlace sin subrayado\n.btn.btn-link {\n  color: $black;\n}\n\n// Elimina el outline de foco de Bootstrap (el diseño usa indicadores propios)\n.btn:focus {\n  box-shadow: none !important;\n}\n\n// Variante con bordes completamente redondeados (pill)\n.btn-circled {\n  border-radius: 75px;\n}\n\n// Color primario: bg, botón primario y hover de botón blanco comparten el mismo verde\n.bg-primary,\n.btn-primary,\n.btn-white:hover {\n  background: $primary-color !important;\n  border-color: $primary-color !important;\n  color: $light;\n}\n\n// Hover del botón primario → negro corporativo\n.bg-dark,\n.btn-primary:hover {\n  background: #232323 !important;\n  border-color: #232323 !important;\n  color: $light;\n}\n\n\n// -----------------------------------------------------------------------------\n// SOMBRAS\n// -----------------------------------------------------------------------------\n\n.shadow-sm-2 {\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n\n.box-shadow {\n  box-shadow: 0 25px 100px -5px rgba(0, 0, 0, .15);\n}\n\n\n// -----------------------------------------------------------------------------\n// FONDOS\n// .bg-cover   → fondo de imagen a pantalla completa, centrado y cubierto\n// .bg-overlay → pseudo-elemento oscuro semitransparente sobre una imagen\n// -----------------------------------------------------------------------------\n\n.bg-cover {\n  background-repeat: no-repeat;\n  background-position: 50%;\n  background-size: cover;\n}\n\n// Posicionamiento absoluto compartido entre bg-cover y bg-overlay\n.bg-cover,\n.bg-overlay,\n.bg-overlay::before {\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n}\n\n// Capa de oscurecimiento del 55% sobre fondos con imagen\n.bg-overlay::before {\n  content: \"\";\n  opacity: .55;\n  background-color: $black;\n}\n\n\n// -----------------------------------------------------------------------------\n// HELPERS DE SPACING Y COLOR\n// -----------------------------------------------------------------------------\n\n// Margen superior de 80px — usado en páginas de proyecto y producto\n// NOTA: el nombre \"mt-80\" refleja el valor real de la propiedad\n.mt-80 {\n  margin-top: 80px;\n}\n\n.mb-30 {\n  margin-bottom: 30px;\n}\n\n// Color de fondo primario como clase utilitaria\n.bg-primary {\n  background: $primary-color !important;\n}\n\n\n// -----------------------------------------------------------------------------\n// ENLACES\n// -----------------------------------------------------------------------------\n\na {\n  color: $primary-color;\n  transition: 0.3s;\n}\n\na:hover,\na:focus {\n  outline: none;\n  text-decoration: none;\n  color: darken($primary-color, 10%);\n}\n","// =============================================================================\r\n// _header.scss\r\n// Estilos para la barra superior (top-bar), barra de logo/contacto (logo-bar),\r\n// navbar principal y el preloader de página.\r\n//\r\n// Estructura del header en el DOM (partials/blocks/navigation.htm):\r\n//   #top-bar          → franja oscura con dirección + redes sociales\r\n//   .logo-bar         → franja blanca con logo + datos de contacto rápido\r\n//   .main-navigation  → navbar Bootstrap con color de marca ($primary-color)\r\n//   #page-loader      → overlay de precarga (oculto por JS al cargar la página)\r\n// =============================================================================\r\n\r\n\r\n/*----------------------\r\n REDES SOCIALES (top-bar)\r\n-----------------------*/\r\n\r\n.header-socials {\r\n  line-height: 22px;\r\n  margin-bottom: 0px;\r\n\r\n  li {\r\n    padding: 8px;\r\n\r\n    a {\r\n      color: $primary-color;\r\n    }\r\n  }\r\n}\r\n\r\n\r\n/*-----------------\r\n LOGO BAR\r\n-------------------*/\r\n\r\n.logo-bar {\r\n  padding: 30px 0px 60px;\r\n}\r\n\r\n.top-info-block {\r\n  margin-right: 30px;\r\n\r\n  h5,\r\n  p {\r\n    margin-bottom: 0px;\r\n  }\r\n}\r\n\r\n\r\n.icon-block {\r\n  margin-right: 20px;\r\n  color: $primary-color;\r\n  font-size: 40px;\r\n  line-height: 20px;\r\n  font-weight: 400;\r\n}\r\n\r\n\r\n.top-info-block:last-child {\r\n  margin-right: 0px;\r\n}\r\n\r\n.header-bar {\r\n  overflow: visible;\r\n  position: relative;\r\n  padding-bottom: 30px;\r\n}\r\n\r\n\r\n.main-navigation {\r\n  margin-top: -40px;\r\n}\r\n\r\n\r\n\r\n\r\n/*-----------------------\r\n HOME-3\r\n---------------------------*/\r\n\r\n.header-white {\r\n  background: $primary-color;\r\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n  border-radius: 0px;\r\n}\r\n\r\n.trans-navigation {\r\n  @include desktop {\r\n    background: $primary-color;\r\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    border-radius: 0px;\r\n  }\r\n}\r\n\r\n.trans-navigation .navbar-brand h4,\r\n.site-navigation .navbar-brand h4,\r\n.site-navigation .navbar-brand h3,\r\n.trans-navigation .navbar-brand h3 {\r\n  color: $light;\r\n}\r\n\r\n.banner-content.style-2 {\r\n  padding-top: 200px;\r\n}\r\n\r\n.trans-navigation .navbar-brand {\r\n  padding-top: 13px;\r\n}\r\n\r\n\r\n\r\n.site-navigation.header-white {\r\n  border-bottom: 1px solid transparent;\r\n}\r\n\r\n.site-navigation .navbar-brand {\r\n  padding-top: 13px;\r\n  margin-right: 20px;\r\n}\r\n\r\n\r\n.banner-content2 {\r\n  padding: 200px 0px;\r\n\r\n  .display-4 {\r\n    color: $light;\r\n    font-weight: 600;\r\n  }\r\n\r\n  p.lead {\r\n    color: $light;\r\n  }\r\n}\r\n\r\n\r\n\r\n\r\n\r\n\r\n/* =========================\r\nPRELOADER\r\n=======================*/\r\n\r\n#page-loader {\r\n  background: $light;\r\n  height: 100%;\r\n  width: 100%;\r\n  position: fixed;\r\n  z-index: 1050;\r\n}\r\n\r\n.loader-icon {\r\n  background: none repeat scroll 0 0 $light;\r\n  border-bottom: 3px solid rgba(19, 19, 19, 0.1) !important;\r\n  border-left: 3px solid rgba(19, 19, 19, 0.1) !important;\r\n  border-radius: 100px;\r\n  -moz-border-radius: 100px;\r\n  -webkit-border-radius: 100px;\r\n  -o-border-radius: 100px;\r\n  -ms-border-radius: 100px;\r\n  border-right: 3px solid #1453F2 !important;\r\n  border-top: 3px solid rgba(19, 19, 19, 0.1) !important;\r\n  height: 50px;\r\n  left: 50%;\r\n  margin: -20px 0 0 -20px;\r\n  position: absolute;\r\n  text-align: center;\r\n  top: 50%;\r\n  width: 50px;\r\n  -webkit-transform: translate(-50%, -50%);\r\n  -ms-transform: translate(-50%, -50%);\r\n  transform: translate(-50%, -50%);\r\n}\r\n\r\n.colored-border {\r\n  border-color: $light;\r\n}\r\n\r\n.fa-spin {\r\n  -webkit-animation: fa-spin 1s infinite linear;\r\n  animation: fa-spin 1s infinite linear;\r\n}\r\n\r\n@-webkit-keyframes fa-spin {\r\n  0% {\r\n    -webkit-transform: rotate(0deg);\r\n    transform: rotate(0deg);\r\n  }\r\n\r\n  100% {\r\n    -webkit-transform: rotate(359deg);\r\n    transform: rotate(359deg);\r\n  }\r\n}\r\n\r\n@keyframes fa-spin {\r\n  0% {\r\n    -webkit-transform: rotate(0deg);\r\n    transform: rotate(0deg);\r\n  }\r\n\r\n  100% {\r\n    -webkit-transform: rotate(359deg);\r\n    transform: rotate(359deg);\r\n  }\r\n}\r\n","// =============================================================================\n// _media-query.scss\n// Mixins de breakpoints para diseño responsive (mobile-first descendente).\n// Uso: @include tablet { ... } dentro de cualquier archivo SCSS.\n//\n// Breakpoints definidos (max-width):\n//   mobile-xs   →  400px  (teléfonos muy pequeños)\n//   mobile      →  480px  (teléfonos pequeños / landscape)\n//   tablet-xs   →  640px  (teléfonos grandes / phablets)\n//   tablet      →  768px  (tablets portrait)\n//   desktop     →  992px  (tablets landscape / laptops pequeños)\n//   large-desktop → 1200px (laptops y escritorios medianos)\n// =============================================================================\n\n\n@mixin mobile-xs {\n  @media (max-width: 400px) {\n    @content;\n  }\n}\n\n@mixin mobile {\n  @media (max-width: 480px) {\n    @content;\n  }\n}\n\n@mixin tablet-xs {\n  @media (max-width: 640px) {\n    @content;\n  }\n}\n\n@mixin tablet {\n  @media (max-width: 768px) {\n    @content;\n  }\n}\n\n@mixin desktop {\n  @media (max-width: 992px) {\n    @content;\n  }\n}\n\n@mixin large-desktop {\n  @media (max-width: 1200px) {\n    @content;\n  }\n}\n","\r\n\r\n/*--------------------------\r\nPAGE BANNER\r\n--------------------------*/\r\n\r\n.page-banner-area{\r\n    padding: 180px 0px;\r\n}\r\n.page-contact{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/p-6.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n.page-service{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/service.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n.page-about{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/about.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n.page-pricing{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/img2.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n.page-project{\r\n    position: relative;\r\n    padding: 180px 0px;\r\n    background: url(\"../images/banner/p-4.jpg\")fixed 50% 50% no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size:cover ;\r\n}\r\n\r\n\r\n.page-banner-content h1{\r\n    color: $light;\r\n}\r\n.page-banner-content p{\r\n    color: $border-color;\r\n}\r\n\r\n.form-control{\r\n    border-radius: 0px;\r\n    height: 45px;\r\n}\r\n","/*-------------------\r\n   MENU\r\n----------------------*/\r\n.navbar-toggler-icon {\r\n  display: inline-block;\r\n  width: 1.5em;\r\n  height: 1.5em;\r\n  content: \"\";\r\n  vertical-align: middle;\r\n  background: no-repeat 50%;\r\n  background-size: 100% 100%\r\n}\r\n\r\n.navbar-dark .navbar-toggler {\r\n  color: #fff;\r\n  border-color: rgba(255,255,255,.1);\r\n  padding: 10px 12px;\r\n  &:focus {\r\n    outline: 0;\r\n  }\r\n}\r\n\r\n.main-nav {\r\n  margin-bottom: -45px;\r\n  z-index: 999;\r\n}\r\n\r\n.navbar-nav .nav-link {\r\n  padding-right: 1rem !important;\r\n  padding-left: 1rem !important;\r\n  transition: .3s;\r\n}\r\n\r\n.navbar-dark .navbar-nav .nav-link {\r\n  color: $light;\r\n  font-weight: 700;\r\n  letter-spacing: .5px;\r\n  text-transform: uppercase;\r\n}\r\n\r\n.rounded-radius {\r\n  border-radius: 5px;\r\n}\r\n\r\n.navbar {\r\n  position: relative;\r\n  padding: 1rem 1rem;\r\n\r\n\r\n  &:before {\r\n    position: absolute;\r\n    z-index: -1;\r\n    top: 0;\r\n    right: 0;\r\n    bottom: 0;\r\n    left: 0;\r\n    content: \"\";\r\n    transition: opacity .15s linear;\r\n    opacity: 0;\r\n    border-bottom: 1px solid rgba(0, 0, 0, .1);\r\n    background-color: $light;\r\n\r\n  }\r\n}\r\n\r\n.dropdown-toggle::after {\r\n  margin-left: .255em;\r\n  vertical-align: 1px;\r\n  content: \"\\f078\";\r\n  border: 0;\r\n  font-family: \"Font Awesome 5 Free\";\r\n  font-size: 12px;\r\n}\r\n\r\n.fixed-top {\r\n  position: fixed;\r\n  z-index: 1030;\r\n  right: 0;\r\n  left: 0;\r\n}\r\n\r\n\r\n.navbar-dark {\r\n  color: $light;\r\n}\r\n\r\n\r\n.navbar-light {\r\n  color: $black;\r\n\r\n  &:before {\r\n    opacity: 1;\r\n  }\r\n}\r\n\r\n\r\n.navbar .nav-item-divider {\r\n  display: none;\r\n\r\n  .nav-link {\r\n    opacity: .25;\r\n  }\r\n}\r\n\r\n.header-bar.fixed-header .main-navigation {\r\n  position: fixed;\r\n  left: 0;\r\n  top: 0;\r\n  width: 100%;\r\n  background: rgba(20, 27, 40, .90);\r\n  border-color: transparent;\r\n\r\n}\r\n\r\n\r\n/*-------------------\r\n  DROPDOWN MENU\r\n----------------------*/\r\n.has-dropdown {\r\n  .dropdown-menu {\r\n    border: none;\r\n    box-shadow: 0 0 25px 0 rgba(0, 0, 0, 0.08);\r\n    padding: 0;\r\n    margin: 0;\r\n\r\n    @include desktop {\r\n      text-align: center;\r\n      float: left !important;\r\n      width: 100%;\r\n      margin: 0;\r\n    }\r\n\r\n    a {\r\n      font-weight: normal;\r\n      color: #808080;\r\n      padding: 10px 20px;\r\n      @include transition (all, 0.3s, ease);\r\n      border-bottom: 1px solid #eee;\r\n      border-radius: 4px;\r\n\r\n      &:focus,\r\n      &:hover {\r\n        background: $primary-color;\r\n        color: $light;\r\n      }\r\n    }\r\n  }\r\n}\r\n\r\n.dropleft .dropdown-menu,\r\n.dropright .dropdown-menu {\r\n  margin: 0;\r\n}\r\n\r\n.dropleft .dropdown-toggle::before,\r\n.dropright .dropdown-toggle::after {\r\n  font-weight: bold;\r\n  font-family: \"Font Awesome 5 Free\";\r\n  border: 0;\r\n  font-size: 10px;\r\n  vertical-align: 1px;\r\n}\r\n\r\n.dropleft .dropdown-toggle::before {\r\n  content: \"\\f053\";\r\n  margin-right: 7px;\r\n}\r\n\r\n.dropright .dropdown-toggle::after {\r\n  content: \"\\f054\";\r\n  margin-left: 7px;\r\n}\r\n\r\n.dropdown-item {\r\n  padding: .6rem 1.4rem;\r\n  text-transform: uppercase;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n}\r\n\r\n.dropdown-submenu:hover>.dropdown-item,\r\n.dropdown-item:hover {\r\n  background: $primary-color;\r\n  color: $light !important;\r\n}\r\n\r\n.dropdown-item.active {\r\n  text-decoration: underline;\r\n  background-color: transparent;\r\n  color: inherit;\r\n}\r\n.dropdown-submenu.active>.dropdown-toggle {\r\n  text-decoration: underline;\r\n  color: inherit;\r\n}\r\n\r\nul.dropdown-menu li {\r\n  padding-left: 0px !important;\r\n}\r\n\r\n@media (min-width:992px) {\r\n  .dropdown-menu {\r\n    transition: all .2s ease-in, visibility 0s linear .2s, transform .2s linear;\r\n    display: block;\r\n    visibility: hidden;\r\n    opacity: 0;\r\n    min-width: 200px;\r\n    transform: translateY(15px);\r\n  }\r\n\r\n  .dropdown:hover>.dropdown-menu {\r\n    visibility: visible;\r\n    transition: all .35s ease 0s;\r\n    opacity: 1;\r\n    transform: translateY(0);\r\n  }\r\n}","// =============================================================================\n// _mixins.scss\n// Mixins de utilidad para propiedades CSS que requieren prefijos de vendor.\n// Usar estos mixins garantiza compatibilidad con navegadores legacy sin\n// repetir prefijos manualmente en cada selector.\n// =============================================================================\n\n\n// -----------------------------------------------------------------------------\n// transition($what, $time, $how)\n// Aplica una transición con todos los prefijos de vendor.\n//\n// @param $what  Propiedad a animar         (default: all)\n// @param $time  Duración de la animación   (default: 0.2s)\n// @param $how   Función de timing          (default: ease-in-out)\n// -----------------------------------------------------------------------------\n@mixin transition($what: all, $time: 0.2s, $how: ease-in-out) {\n  -webkit-transition: $what $time $how;\n  -moz-transition:    $what $time $how;\n  -ms-transition:     $what $time $how;\n  -o-transition:      $what $time $how;\n  transition:         $what $time $how;\n}\n\n\n// -----------------------------------------------------------------------------\n// transform($transforms)\n// Mixin base para aplicar cualquier función transform con prefijos de vendor.\n// Los mixins rotate, scale, translate y skew lo usan internamente.\n//\n// @param $transforms  Valor(es) de la propiedad CSS transform\n// -----------------------------------------------------------------------------\n@mixin transform($transforms) {\n  -webkit-transform: $transforms;\n  -moz-transform:    $transforms;\n  -ms-transform:     $transforms;\n  -o-transform:      $transforms;\n  transform:         $transforms;\n}\n\n\n// -----------------------------------------------------------------------------\n// Utilidades de transform — envoltorios semánticos sobre @mixin transform\n// -----------------------------------------------------------------------------\n\n// Rotar $deg grados\n@mixin rotate($deg) {\n  @include transform(rotate(#{$deg}deg));\n}\n\n// Escalar el elemento por un factor $scale\n@mixin scale($scale) {\n  @include transform(scale($scale));\n}\n\n// Trasladar el elemento ($x, $y)\n@mixin translate($x, $y) {\n  @include transform(translate($x, $y));\n}\n\n// Inclinar el elemento ($x grados en X, $y grados en Y)\n@mixin skew($x, $y) {\n  @include transform(skew(#{$x}deg, #{$y}deg));\n}\n\n\n// -----------------------------------------------------------------------------\n// transform-origin($origin)\n// Define el punto de origen de la transformación con prefijos de vendor.\n//\n// @param $origin  Valor CSS de transform-origin (ej: \"50% 50%\", \"top left\")\n// -----------------------------------------------------------------------------\n@mixin transform-origin($origin) {\n  -webkit-transform-origin: $origin;\n  -moz-transform-origin:    $origin;  // Corregido: prefijo -moz- (antes faltaba el guion)\n  -ms-transform-origin:     $origin;\n  -o-transform-origin:      $origin;\n  transform-origin:         $origin;\n}\n","\r\n/*----------------------\r\n BANNER STYLE\r\n-----------------------*/\r\n\r\n.py-7 {\r\n    padding: 7.5rem 0;\r\n}\r\n\r\n.py-8 {\r\n    padding: 8.5rem 0;\r\n}\r\n\r\n\r\n.main-banner {\r\n    h5{\r\n        margin-bottom: 20px;\r\n    }\r\n    h1.display-4{\r\n        line-height: 65px;\r\n    }\r\n}\r\n\r\n\r\n.main-banner p.lead,\r\n.banner-content p.lead{\r\n    margin-bottom: 2.5rem!important;\r\n}\r\n\r\n\r\n\r\n/*-------------------------\r\n HOME -2 \r\n-----------------------------*/\r\n#banner{\r\n    position: relative;\r\n    background: url(\"/images/bg/banner_bg.jpg\")no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size: cover;\r\n}\r\n\r\n\r\n.banner-content {\r\n    padding: 150px 0px;\r\n    padding-right: 30px;\r\n    p{\r\n        color: $border-color;\r\n        padding-right: 80px;\r\n        margin-bottom: 30px !important;\r\n    }\r\n    .display-4{\r\n        color: $light;\r\n        font-weight: 600;\r\n    }\r\n}\r\n\r\n\r\n#banner .overlay{\r\n    opacity: .7;\r\n}\r\n\r\n.banner-contact-form{\r\n    padding:45px 40px;\r\n    margin-top: 30px;\r\n\r\n    .form-control{\r\n        border-radius: 0px;\r\n        height: 45px;\r\n    }\r\n\r\n    textarea.form-control{\r\n        height: auto;\r\n    }\r\n}\r\n","\r\n#banner-3{\r\n    position: relative;\r\n    background: url(\"../images/banner/banner.jpg\")no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size: cover;\r\n}\r\n\r\n#banner-4{\r\n    position: relative;\r\n    background: url(\"../images/banner/banner-2.jpg\")no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size: cover;\r\n}\r\n\r\n","\r\n/*----------------------\r\n FEATURE STYLE\r\n-----------------------*/\r\n.img-icon-block {\r\n    position: relative;\r\n\r\n    &:before {\r\n        position: absolute;\r\n        content: \"\";\r\n        top: -27px;\r\n        background-color: $primary-color;\r\n        opacity: .3;\r\n        width: 80px;\r\n        right: 70px;\r\n        height: 80px;\r\n        border-radius: 50%;\r\n        z-index: 1;\r\n    }\r\n\r\n    i{\r\n        font-size: 58px;\r\n        z-index: 2!important;\r\n        color: #333;\r\n        position: relative;\r\n    }\r\n}\r\n\r\n\r\n\r\n\r\n\r\n/*--------------------------\r\nABOUT-2\r\n---------------------------*/\r\n#about .img-block{\r\n    position: relative;\r\n      -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n\r\n    img{\r\n        border: 5px solid $primary-color;\r\n    }\r\n}\r\n.pt-6{\r\n    padding-top: 4.5rem;\r\n}\r\n.img-icon i{\r\n    font-size: 60px;\r\n}\r\n","/*----------------------\r\n SERVICE\r\n-----------------------*/\r\nh5.subtitle {\r\n  color: $primary-color;\r\n  margin-bottom: 10px;\r\n  font-weight: 300;\r\n}\r\n\r\n.service-heading {\r\n  margin-bottom: 50px;\r\n}\r\n\r\n.service-images {\r\n  margin-bottom: -200px;\r\n  border: 10px solid $light;\r\n  z-index: 9999;\r\n}\r\n\r\n.service-content {\r\n  padding-top: 60px;\r\n  padding-left: 15px;\r\n\r\n  h1 {\r\n    margin-bottom: 20px;\r\n    margin-top: 15px;\r\n  }\r\n}\r\n\r\n.service-icon {\r\n  margin-right: 20px;\r\n  color: $light;\r\n  font-size: 25px;\r\n  width: 50px;\r\n  height: 50px;\r\n  background: $primary-color;\r\n  text-align: center;\r\n  border-radius: 50%;\r\n  padding-top: 5px;\r\n}\r\n\r\n.service-block {\r\n  margin-bottom: 50px;\r\n}\r\n\r\n\r\n.service-inner-content h4 {\r\n  text-transform: uppercase;\r\n}\r\n\r\n\r\n/*----------------------\r\n WEB SERVICES\r\n-----------------------*/\r\n#services-2 {\r\n  position: relative;\r\n  background: url(\"../images/bg/6.jpg\")no-repeat fixed 50% 50%;\r\n  -webkit-background-size: cover;\r\n  background-size: cover;\r\n\r\n  &:before {\r\n    position: absolute;\r\n    content: \"\";\r\n    left: 0px;\r\n    top: 0px;\r\n    width: 100%;\r\n    height: 100%;\r\n    background-image: linear-gradient(30deg, rgba(121, 110, 255, 0.95) 0%, rgba(33, 200, 122, 0.95) 100%);\r\n  }\r\n}\r\n\r\n\r\n.web-service-block {\r\n  text-align: center;\r\n  padding: 35px 25px;\r\n  transition: .3s;\r\n  border-radius: 10px;\r\n  border: 1px solid rgba(255, 255, 255, 0.05);\r\n  margin-bottom: 10px;\r\n\r\n  i {\r\n    font-size: 70px;\r\n    margin-bottom: 30px;\r\n    display: block;\r\n    color: $light;\r\n  }\r\n\r\n  h3 {\r\n    color: $light;\r\n    transition: 0.3s;\r\n  }\r\n\r\n  p {\r\n    color: $border-color;\r\n    margin-top: 15px;\r\n    transition: 0.3s;\r\n  }\r\n\r\n  &:hover {\r\n    background: $light;\r\n    border-color: transparent;\r\n\r\n    i {\r\n      color: $primary-color;\r\n    }\r\n\r\n    h3 {\r\n      color: #111;\r\n    }\r\n\r\n    p {\r\n      color: #111;\r\n    }\r\n  }\r\n}\r\n\r\n.service-img {\r\n  margin-bottom: -200px;\r\n  border: 10px solid $light;\r\n  z-index: 9999;\r\n\r\n}","// =============================================================================\r\n// _portfolio.scss\r\n// Estilos para las secciones de proyectos:\r\n//   #projects-wrap       → sección hero de proyectos (fondo con imagen)\r\n//   .project-content     → tarjeta de proyecto individual\r\n//   .project-content-block → bloque informativo superpuesto en proyectos destacados\r\n//   .single-work / .work-block → grid de portfolio con efecto hover\r\n//   .project-details-info → página de detalle de proyecto individual\r\n// =============================================================================\r\n\r\n\r\n/*----------------------\r\n SECCIÓN PROYECTOS DESTACADOS\r\n-----------------------*/\r\n#projects-wrap {\r\n    position: relative;\r\n    background: url(\"../images/bg/banner_bg.jpg\")no-repeat;\r\n    -webkit-background-size: cover;\r\n    background-size: cover;\r\n\r\n    p.lead{\r\n        color: #a9a9a9!important;\r\n    }\r\n}\r\n\r\n.overlay {\r\n    position: absolute;\r\n    left: 0;\r\n    top: 0;\r\n    width: 100%;\r\n    height: 100%;\r\n    background: rgba(0, 0, 0, .92);\r\n}\r\n\r\n.overlay.feature-overlay {\r\n    background-image: linear-gradient(30deg, rgba(121, 110, 255, 0.95) 0%, rgba(33, 200, 122, 0.95) 100%);\r\n    opacity: .9;\r\n}\r\n\r\n#projects {\r\n    margin-top: -60px;\r\n}\r\n\r\n.single-project img {\r\n    border-radius: 10px;\r\n}\r\n\r\n.project-content {\r\n    text-align: center;\r\n    padding: 40px 20px;\r\n    position: relative;\r\n    .btn {\r\n        padding: .7rem 1.7rem;\r\n        border-radius: 25px;\r\n    }\r\n    p {\r\n       margin-top: 20px;\r\n    }\r\n    h4 {\r\n        text-transform: capitalize;\r\n    }\r\n}\r\n\r\n.project-content-block {\r\n    padding: 70px 40px;\r\n    margin-left: -120px;\r\n    background: $secondary-color;\r\n    position: absolute;\r\n    bottom: -70px;\r\n    border: 15px solid $light;\r\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    h4 {\r\n        color: $primary-color;\r\n    }\r\n    p {\r\n        margin-top: 25px;\r\n    }\r\n\r\n}\r\n\r\n\r\n/*-------------------------\r\n PORTFOLIO-2\r\n---------------------------*/\r\n\r\n.single-work {\r\n    -webkit-transition: all 300ms ease-in-out;\r\n    -o-transition:  all 300ms ease-in-out;\r\n    transition:  all 300ms ease-in-out;\r\n}\r\n\r\n\r\n\r\n\r\n.overlay-content-block{\r\n    position: absolute;\r\n    content: \"\";\r\n    bottom: 20px;\r\n    width: 100%;\r\n    left: 30px;\r\n    padding: 30px 20px;\r\n    background: $light;\r\n    opacity: 0;\r\n    visibility: hidden;\r\n    -webkit-transition: all 300ms ease-in-out;\r\n    -o-transition:  all 300ms ease-in-out;\r\n    transition:  all 300ms ease-in-out;\r\n    border-radius: 5px 0px 0px 5px;\r\n\r\n    a{\r\n        width: 50px;\r\n        height: 50px;\r\n        display: inline-block;\r\n        text-align: center;\r\n        padding-top: 12px;\r\n        border-radius: 100%;\r\n        position: absolute;\r\n        left: 30px;\r\n        top: -23px;\r\n        background: $primary-color;\r\n        color: $light;\r\n    }\r\n\r\n    h4{\r\n        margin-bottom: 0px;\r\n        margin-top: 10px;\r\n    }\r\n}\r\n\r\n.work-block{\r\n    position: relative;\r\n    border: 5px solid $light;\r\n\r\n    img{\r\n        width: 100%;\r\n        border-radius: 5px;\r\n    }\r\n    \r\n    &:hover .overlay-content-block{\r\n        opacity: 1;\r\n        visibility: visible;\r\n    }\r\n}\r\n\r\n\r\n\r\n\r\n/* ==============================\r\n  SINGEL PROJECTS\r\n=============================*/\r\n\r\n.project-details-info{\r\n   margin: 40px 0px;\r\n}\r\n\r\n.info-block-2{\r\n    float: left;\r\n    margin-right: 65px;\r\n    margin-bottom: 40px;\r\n}\r\n\r\n.project-info ul {\r\n    margin-top: 40px;\r\n    li{\r\n        margin-bottom: 30px;\r\n        padding-right: 20px;\r\n    }\r\n}\r\n\r\n.project-lg-images img {\r\n    width: 100%;\r\n}\r\n","\r\n\r\n/*----------------------\r\n PROCESS\r\n-----------------------*/\r\n.process-block {\r\n    text-align: center;\r\n     img {\r\n\t    border-radius: 5px;\r\n\t    margin-bottom: 30px;\r\n\t}\r\n\th3 {\r\n\t    margin-bottom:15px;\r\n\t}\r\n\r\n}\r\n","\r\n\r\n/*----------------------\r\n PRICING\r\n-----------------------*/\r\n\r\n.price-block {\r\n    margin: 20px 0px 30px;\r\n    h2 {\r\n        font-size: 80px;\r\n        font-weight: 700;\r\n        position: relative;\r\n        display: inline-block;\r\n\r\n        small {\r\n            position: absolute;\r\n            top: 20px;\r\n            font-size: 16px;\r\n            left: -9px;\r\n        }\r\n    }\r\n\r\n     h6 {\r\n        font-size: 14px;\r\n        border-top: 1px solid $border-color;\r\n        border-bottom: 1px solid $border-color;\r\n        padding: 7px;\r\n        text-transform: capitalize;\r\n        width: 50%;\r\n        margin: 10px auto;\r\n\r\n    }\r\n}\r\n\r\n\r\n\r\n.price-features {\r\n    margin: 30px 0px 50px;\r\n    li {\r\n        font-size: 16px;\r\n        padding: 5px 0px;\r\n        position: relative;\r\n        padding-left: 30px;\r\n\r\n        &:before{\r\n            position: absolute;\r\n            content:\"\\f00c\";\r\n            font-family: \"Font Awesome 5 Free\";\r\n            left: 0px;\r\n            top: 5px;\r\n            color: $primary-color;\r\n            font-weight: 900;\r\n        }\r\n    }\r\n}\r\n\r\n\r\n\r\n.pricing-block .price-features li{\r\n    padding-left: 0px;\r\n    &:before{\r\n        display: none;\r\n    }\r\n}\r\n\r\n\r\n\r\n/*--------------------------\r\nPRICING-2\r\n---------------------------*/\r\n.pricing-box{\r\n    border: 1px solid $border-color;\r\n    padding: 60px;\r\n    -webkit-transition: all 300ms ease-in-out;\r\n    -o-transition:all 300ms ease-in-out ;\r\n    transition:all 300ms ease-in-out ;\r\n\r\n    .price-block h2 span{\r\n        font-size: 12px;\r\n        font-weight: normal;\r\n        text-transform: capitalize;\r\n    }\r\n    &:hover{\r\n        background: rgb(29, 28, 28);\r\n        border-color: rgb(29, 28, 28);\r\n    }\r\n\r\n    &:hover .price-features li{\r\n        color: $border-color;\r\n    }\r\n    &:hover .price-block h2{\r\n        color: $light;\r\n    }\r\n    &:hover h3{\r\n        color: $light;\r\n    }\r\n    &:hover .btn{\r\n        background: $light!important;\r\n        color: #000!important;\r\n    }\r\n\r\n}\r\n\r\n","\r\n\r\n/*----------------------\r\n BLOG SECTION\r\n-----------------------*/\r\n.blog-box {\r\n    position: relative;\r\n\r\n    .blog-img-box img {\r\n        border-radius: 5px;\r\n        box-shadow: 0 7px 12px rgba(0, 0, 0, 0.08);\r\n    }\r\n}\r\n\r\n\r\n\r\n\r\n.single-blog {\r\n    padding-top: 25px;\r\n    position: relative;\r\n}\r\n\r\n.bg-light .single-blog{\r\n    padding: 40px;\r\n    text-align: center;\r\n    border-bottom: 1px solid $border-color;\r\n}\r\n\r\n\r\n.blog-content {\r\n    ul {\r\n        margin-bottom: 10px;\r\n    }\r\n    a h3 {\r\n        transition: all .3s ease 0s;\r\n        margin: 15px 0px;\r\n    }\r\n    p{\r\n        margin: 20px 0px;\r\n    }\r\n\r\n    &:hover a h3 {\r\n        color: $primary-color;\r\n    }\r\n\r\n    h6 span{\r\n        display: inline-block;\r\n        padding-left: 10px;\r\n\r\n        &:after{\r\n            display: none;\r\n        }\r\n    }\r\n\r\n}\r\n\r\n","/*------------------------------------\r\nSECTION TESTIMONIAL\r\n-------------------------------------*/\r\n#section-testimonial{\r\n    padding-bottom: 120px;\r\n    background: #F9FAFF;\r\n}\r\n.mb25{\r\n    margin-bottom: 25px;\r\n}\r\n.test-inner{\r\n    position: relative;\r\n    padding: 30px;\r\n    background: $light;\r\n    border-top-right-radius: 35px;\r\n    margin-bottom: 25px;\r\n    -webkit-transition: all .7s ease;\r\n    -o-transition:all .7s ease ;\r\n    transition:all .7s ease ;\r\n\r\n    &:hover{\r\n         -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n        box-shadow:0 7px 22px rgba(0, 0, 0, 0.08) ;\r\n    }\r\n\r\n    i{\r\n        font-size: 60px;\r\n        opacity: .09;\r\n        position: absolute;\r\n        right: 40px;\r\n        bottom: 20px;\r\n    }\r\n}\r\n\r\n\r\n.test-author-thumb{\r\n    margin-bottom: 15px;\r\n    img{\r\n        width: 90px;\r\n        height: 90px;\r\n        border-radius: 100%;\r\n        border: 1px dotted #ddd;\r\n        padding: 5px;\r\n    }\r\n}\r\n\r\n.test-author-info{\r\n    margin-left: 20px;\r\n    margin-top: 20px;\r\n}\r\n\r\n\r\n\r\n\r\n/*----------------------\r\n TETSIMONIAL-2\r\n-------------------------*/\r\n\r\n.testimonial .content img{\r\n    margin: 0 auto 30px;\r\n    border: 3px solid $light;\r\n}\r\n\r\n.img-md{\r\n    width: 120px;\r\n    height: 120px;\r\n    border-radius: 100%;\r\n}","\r\n/*---------------------------\r\nCONTACT PAGE\r\n-----------------------------*/\r\n\r\n#contact-info{\r\n    padding-top: 90px;\r\n}\r\n.contact-info-block{\r\n    border: 1px solid $border-color;\r\n    padding: 40px 20px;\r\n    border-radius: 5px;\r\n\r\n     h4{\r\n        margin-bottom: 0px;\r\n    }\r\n    i{\r\n        font-size: 40px;\r\n        margin-bottom: 20px;\r\n        display: block;\r\n        color: $primary-color;\r\n    }\r\n}\r\n\r\n\r\n.form-control:focus,.form-control:hover{\r\n    border-color: $primary-color;\r\n    box-shadow: none;\r\n}\r\n\r\n\r\n/* --------------\r\n    MAP\r\n-----------------*/\r\n\r\n#map{\r\n    height: 400px;\r\n    width: 100%;\r\n}","/*----------------------\r\n FOOTER\r\n-----------------------*/\r\n#footer {\r\n  padding: 80px 0px;\r\n  position: relative;\r\n\r\n  .footer-brand {\r\n    font-size: 30px;\r\n  }\r\n\r\n  .footer-links {\r\n    padding-left: 0;\r\n    list-style-type: none\r\n  }\r\n\r\n}\r\n\r\n#footer {\r\n  background: url(\"../images/bg/10.jpg\");\r\n  -webkit-background-size: cover;\r\n  background-size: cover;\r\n}\r\n\r\n.footer-overlay {\r\n  background: #111;\r\n  opacity: .94;\r\n}\r\n\r\n\r\n\r\n\r\n.footer-widget {\r\n  p {\r\n    color: $black-lighter;\r\n    margin-top: 20px;\r\n    margin-bottom: 20px;\r\n    line-height: 32px;\r\n    font-size: 14px;\r\n  }\r\n\r\n  h3 {\r\n    color: $light;\r\n    margin-bottom: 30px;\r\n  }\r\n}\r\n\r\n\r\n\r\n.footer-links {\r\n  a {\r\n    color: $black-lighter;\r\n    line-height: 38px;\r\n    font-size: 14px;\r\n    text-transform: capitalize;\r\n  }\r\n  i {\r\n    width: 25px;\r\n  }\r\n}\r\n\r\n\r\n.footer-copy {\r\n  color: $black-lighter;\r\n  font-size: 16px;\r\n  position: relative;\r\n  margin-bottom: 0;\r\n  display: inline-block;\r\n\r\n  &:before {\r\n    position: absolute;\r\n    content: \"\";\r\n    right: calc(100% + 30px);\r\n    top: 16px;\r\n    width: 2000%;\r\n    height: 1px;\r\n    height: 1px;\r\n    background: #94959a;\r\n  }\r\n}\r\n.current-year {\r\n  color: $primary-color !important;\r\n}\r\n\r\n\r\n\r\n\r\n/*-----------------------------\r\n SCROLL TO TOP\r\n--------------------------------*/\r\n.scroll-to-top {\r\n  position: fixed;\r\n  content: \"\";\r\n  right: 30px;\r\n  bottom: 50px;\r\n  z-index: 999;\r\n  background: $primary-color;\r\n  color: $light !important;\r\n  border-radius: 100%;\r\n  opacity: 0;\r\n\r\n  i {\r\n    width: 50px;\r\n    height: 50px;\r\n    border-radius: 100%;\r\n    text-align: center;\r\n    font-size: 22px;\r\n    line-height: 50px;\r\n    display: block;\r\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\r\n  }\r\n}\r\n\r\n.scroll-to-top:hover,\r\n.scroll-to-top:focus {\r\n  text-decoration: none;\r\n}\r\n\r\n.reveal {\r\n  transition: all .3s;\r\n  cursor: pointer;\r\n  opacity: 1;\r\n}\r\n","// =============================================================================\r\n// _responsive.scss\r\n// Overrides de componentes específicos para cada br